function getHeader(msg, name) {
  return msg[name] || '';
}

function decodeBody(payload) {
  function findBody(part) {
    if (part.mimeType === 'text/plain' && part.body?.data) {
      return Buffer.from(part.body.data, 'base64').toString('utf-8');
    }
    if (part.parts) {
      for (const p of part.parts) {
        const result = findBody(p);
        if (result) return result;
      }
    }
    return '';
  }
  return findBody(payload) || (payload.body?.data
    ? Buffer.from(payload.body.data, 'base64').toString('utf-8')
    : '');
}

function findAttachments(part, results = []) {
  if (part.filename && part.filename.trim() !== '') {
    results.push(part.filename);
  }
  if (part.parts) {
    part.parts.forEach(p => findAttachments(p, results));
  }
  return results;
}

function cleanBody(body) {
  // 1. Strip Google Groups footer (starts with "-- " signature delimiter)
  let cleaned = body.split(/\r?\n--\s*\r?\n/)[0];
  // 2. Strip quoted reply chain — [\s\S]{0,150} allows the "On ... wrote:" preamble
  //    to span a line break (long sender names/dates wrap), unlike "." which stops at \n
  cleaned = cleaned.split(/\r?\n\r?\nOn [\s\S]{0,150}?wrote:[\s\S]*/)[0];
  return cleaned.trim();
}

function parseFrom(fromHeader) {
  const name = fromHeader.split('<')[0].trim().replace(/"/g, '');
  const emailMatch = (fromHeader.match(/<(.+)>/) || [, fromHeader])[1];
  return { name, email: emailMatch };
}

const thread = $input.first().json;
const messages = thread.messages || [];

const rows = messages.map(msg => {
  const from = parseFrom(getHeader(msg, 'From'));
  const to = getHeader(msg, 'To');
  const attachments = findAttachments(msg.payload);
  return {
    Email_ID: msg.id,
    Thread_ID: msg.threadId,
    Sent_Timestamp: new Date(parseInt(msg.internalDate)).toISOString(),
    Channel_Type: 'Email',
    From_Name: from.name,
    From_Email: from.email,
    To_Group: to,
    CC: getHeader(msg, 'Cc'),
    Subject: getHeader(msg, 'Subject'),
    Email_Body: cleanBody(decodeBody(msg.payload)),
    Attachment_Name: attachments.join('; '),
  };
});

rows.sort((a, b) => new Date(a.Sent_Timestamp) - new Date(b.Sent_Timestamp));
rows.forEach((r, i) => r.Thread_Sequence = i + 1);

rows.forEach(r => {
  r.Thread_Title = '';
  r.Department = '';
  r.Conversation_Category = '';
  r.Client_Project_or_Topic = '';
  r.Sender_Role = '';
  r.Priority = '';
});

return rows.map(r => ({ json: r }));

let raw = $input.first().json.text || $input.first().json.output || '';
raw = raw.trim().replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

let aiOutput;
try {
  aiOutput = JSON.parse(raw);
} catch (e) {
  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    aiOutput = JSON.parse(match[0]);
  } else {
    throw new Error('AI did not return valid JSON: ' + raw.substring(0, 200));
  }
}

const originalRows = $('Code in JavaScript').all().map(item => item.json);
const threadId = originalRows[0].Thread_ID;

// Output 1: realdb rows (one per email)
const realdbRows = originalRows.map(row => ({
  email_id: row.Email_ID,
  thread_id: row.Thread_ID,
  thread_sequence: row.Thread_Sequence,
  channel_type: row.Channel_Type,
  department: aiOutput.department || '',
  conversation_category: aiOutput.conversation_category || '',
  client_project_or_topic: aiOutput.client_project_or_topic || '',
  thread_title: aiOutput.thread_title || '',
  sent_timestamp: row.Sent_Timestamp,
  from_name: row.From_Name,
  from_email: row.From_Email,
  sender_role: aiOutput.sender_role || '',
  to_group: row.To_Group,
  cc: row.CC,
  subject: row.Subject,
  email_body: row.Email_Body,
  attachment_name: row.Attachment_Name,
  priority: aiOutput.priority || '',
  summary: aiOutput.summary || '',
  _target: 'realdb',
}));

// Output 2: tasks rows (one per extracted task)
const tasks = Array.isArray(aiOutput.tasks) ? aiOutput.tasks : [];
const taskRows = tasks.map((t, i) => ({
  task_id: `${threadId}_${i + 1}`,
  thread_id: threadId,
  task: t.task || '',
  owner: t.owner || null,
  due_date: t.due_date || null,
  status: t.status || 'open',
  _target: 'tasks',
}));

// Output 3: Neo4j payload (one object per thread)
const neo4jPayload = [{
  thread_id: threadId,
  thread_title: aiOutput.thread_title || '',
  department: aiOutput.department || '',
  topic: aiOutput.client_project_or_topic || '',
  people: [...new Set(originalRows.map(r => JSON.stringify({ name: r.From_Name, email: r.From_Email })))].map(s => JSON.parse(s)),
  tasks: taskRows.map(t => ({ task_id: t.task_id, task: t.task, owner: t.owner, due_date: t.due_date, status: t.status })),
  _target: 'neo4j',
}];

return [...realdbRows, ...taskRows, ...neo4jPayload].map(r => ({ json: r }));

