// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}// Combines all per-email rows from Code node 1 into one text blob for the AI
const items = $input.all();
const rows = items.map(item => item.json);

// Build a readable conversation transcript, oldest first (already sorted upstream)
const conversationText = rows.map(r =>
  `[${r.Sent_Timestamp}] ${r.From_Name} (${r.From_Email}):\n${r.Email_Body}`
).join('\n\n---\n\n');

const firstRow = rows[0];

return [{
  json: {
    Thread_ID: firstRow.Thread_ID,
    original_subject: firstRow.Subject,
    conversation_text: conversationText,
    message_count: rows.length,
  }
}];

return $input.all();
